SELECT 'bulk_rpc_access' AS audit_section, to_regprocedure('public.undo_shipments_v1(uuid[])') IS NOT NULL AS function_exists, has_function_privilege('anon', to_regprocedure('public.undo_shipments_v1(uuid[])'), 'EXECUTE') AS anon_can_execute, has_function_privilege('authenticated', to_regprocedure('public.undo_shipments_v1(uuid[])'), 'EXECUTE') AS authenticated_can_execute; SELECT 'shipment_value_summary' AS audit_section, count(*) AS active_shipment_lines, count(*) FILTER (WHERE t.unit_cost IS NULL) AS lines_missing_saved_price, count(*) FILTER (WHERE t.unit_cost IS NULL AND p.unit_price IS NULL) AS lines_missing_all_price, COALESCE(sum(t.qty * COALESCE(t.unit_cost, p.unit_price, 0)), 0) AS displayed_total_value FROM public.inventory_transactions t JOIN public.shipment_logs s ON s.id = t.shipment_id AND s.deleted_at IS NULL LEFT JOIN public.products p ON p.id = t.product_id WHERE t.deleted_at IS NULL; SELECT 'shipments_missing_price' AS audit_section, s.shipment_no, s.shipment_date, count(*) FILTER (WHERE t.unit_cost IS NULL) AS lines_missing_saved_price, count(*) FILTER (WHERE t.unit_cost IS NULL AND p.unit_price IS NULL) AS lines_missing_all_price FROM public.shipment_logs s JOIN public.inventory_transactions t ON t.shipment_id = s.id AND t.deleted_at IS NULL LEFT JOIN public.products p ON p.id = t.product_id WHERE s.deleted_at IS NULL GROUP BY s.id, s.shipment_no, s.shipment_date HAVING count(*) FILTER (WHERE t.unit_cost IS NULL) > 0 ORDER BY s.shipment_date DESC, s.shipment_no DESC LIMIT 100;
